// src/shared/db/repositories/backupRepository.ts
var BackupRepository = class {
  db;
  constructor(dbClient) {
    this.db = dbClient;
  }
  /**
   * 获取所有启用的备份提供商配置 (按名称排序)
   */
  async findAllSettings() {
    return await this.db.select().from(backupProviders4).orderBy(desc(backupProviders4.updatedAt));
  }
  /**
   * 根据提供商类型获取配置
   */
  async findByType(type) {
    const result = await this.db.select().from(backupProviders4).where(eq(backupProviders4.type, type)).limit(1);
    return result[0];
  }
  /**
   * 保存或更新某个提供商的配置
   */
  async upsert(type, data) {
    const existing = await this.findByType(type);
    if (existing) {
      await this.db.update(backupProviders4).set({ ...data, updatedAt: Date.now() }).where(eq(backupProviders4.type, type));
      const result = await this.findByType(type);
      return result;
    } else {
      const insertData = {
        type,
        name: data.name || type.toUpperCase(),
        config: data.config || "{}",
        isEnabled: data.isEnabled ?? true,
        autoBackup: data.autoBackup ?? false,
        autoBackupPassword: data.autoBackupPassword || null,
        createdAt: Date.now(),
        updatedAt: Date.now()
      };
      await this.db.insert(backupProviders4).values(insertData);
      const result = await this.findByType(type);
      return result;
    }
  }
};

