app.use("/api/*", cors({
  origin: (origin) => origin,
  credentials: true,
  allowHeaders: ["Content-Type", "Authorization", "X-CSRF-Token"],
  allowMethods: ["POST", "GET", "OPTIONS", "PUT", "DELETE"],
  maxAge: 86400
}));
