// src/shared/db/factory.ts
import fs2 from "fs";
import path4 from "path";
var DbFactory = class {
  static async create() {
    const engine2 = (process.env.DB_ENGINE || "sqlite").toLowerCase();
    const baseDir = process.cwd();
    switch (engine2) {
      // ... (mysql/postgres 保持不变)
      case "mysql": {
        const config = {
          host: process.env.DB_HOST,
          port: parseInt(process.env.DB_PORT || "3306", 10),
          user: process.env.DB_USER,
          password: process.env.DB_PASSWORD,
          database: process.env.DB_NAME,
          ssl: process.env.DB_SSL === "true"
        };
        const executor = new MySqlExecutor(config);
        const db = drizzle2(executor.pool, { schema: mysql_exports, mode: "default" });
        return { executor, db, schema: mysql_exports };
      }
      case "postgres":
      case "postgresql": {
        const config = { host: process.env.DB_HOST, port: parseInt(process.env.DB_PORT || "5432", 10), user: process.env.DB_USER, password: process.env.DB_PASSWORD, database: process.env.DB_NAME, ssl: process.env.DB_SSL === "true" };
        const executor = new PgExecutor(config);
        const db = drizzle3(executor.pool, { schema: pg_exports });
        return { executor, db, schema: pg_exports };
      }
      case "sqlite":
      default: {
        const rawPath = (process.env.SQLITE_DB_PATH || "./data/nodeauth.db").trim();
        const dbFile = path4.isAbsolute(rawPath) ? rawPath : path4.resolve(baseDir, rawPath);
        logger2.info(`[Database] Engine: SQLite. Resolved path: "${dbFile}"`);
        const dbDir = path4.dirname(dbFile);
        if (!fs2.existsSync(dbDir)) {
          logger2.info(`[Database] Creating missing directory: "${dbDir}"`);
          fs2.mkdirSync(dbDir, { recursive: true });
        }
        try {
          const testFile = path4.join(path4.dirname(dbFile), ".write_test");
          fs2.writeFileSync(testFile, "ok");
          fs2.unlinkSync(testFile);
          logger2.info(`[Database] Write Test PASSED for: "${path4.dirname(dbFile)}"`);
        } catch (e2) {
          logger2.error(`[Database] Write Test FAILED: ${e2.message}`);
        }
        const sqlite = new Database(dbFile);
        sqlite.pragma("journal_mode = WAL");
        const executor = new SqliteExecutor(sqlite);
        const db = drizzle(sqlite, { schema: sqlite_exports });
        return { executor, db, schema: sqlite_exports };
      }
    }
  }
};

